export const CONTENT_HTML = "\r\n<p class=\"intro\">Tại sao một bức tranh phong cảnh trông như \"thật sâu\"? Tại sao các họa sĩ Renaissance như Leonardo da Vinci vẽ được không gian thuyết phục? Câu trả lời gói gọn trong một từ: <strong>phối cảnh</strong>.</p>\r\n\r\n<div class=\"stats break-half\">\r\n  <div class=\"stat\"><div class=\"stat-num\">3</div><div class=\"stat-label\">Loại phối cảnh</div><div class=\"stat-sub\">1, 2, 3 điểm tụ</div></div>\r\n  <div class=\"stat\"><div class=\"stat-num\">1415</div><div class=\"stat-label\">Năm khám phá</div><div class=\"stat-sub\">Brunelleschi</div></div>\r\n  <div class=\"stat\"><div class=\"stat-num\">90°</div><div class=\"stat-label\">Cone of vision</div><div class=\"stat-sub\">Góc nhìn tự nhiên</div></div>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>01</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Định nghĩa</p>\r\n    <h2 class=\"div-title\">Phối cảnh là gì?</h2>\r\n  </div>\r\n</div>\r\n\r\n<p><strong>Phối cảnh</strong> <em>(Perspective)</em> là hệ thống quy luật mô tả cách vật thể 3D được chiếu lên mặt phẳng 2D sao cho trông như thật. Cốt lõi: <strong>vật xa trông nhỏ hơn vật gần</strong>, và các đường thẳng song song trong thực tế sẽ hội tụ về <em>điểm tụ</em> trên giấy.</p>\r\n\r\n<div class=\"gls\">\r\n  <p class=\"gls-head\">A — Thuật ngữ phối cảnh</p>\r\n  <div class=\"gls-body\">\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Horizon Line<small>Đường chân trời</small></p><p class=\"gls-def\">Đường ngang tầm mắt người vẽ. Quyết định mọi thứ khác.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Vanishing Point<small>Điểm tụ</small></p><p class=\"gls-def\">Điểm trên đường chân trời nơi các đường song song hội tụ.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Picture Plane<small>Mặt phẳng tranh</small></p><p class=\"gls-def\">Mặt phẳng ảo giữa mắt người vẽ và đối tượng.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Foreshortening<small>Rút gọn</small></p><p class=\"gls-def\">Vật hướng về phía người xem trông ngắn lại.</p></div>\r\n  </div>\r\n</div>\r\n\r\n<!-- 🖼️ GALLERY-3 · 3 loại phối cảnh -->\r\n<div class=\"gallery gallery-3\">\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/ly-thuyet-phoi-canh/gallery-3-1.png\" alt=\"Phối cảnh 1 điểm\" />\r\n  </figure>\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/ly-thuyet-phoi-canh/gallery-3-2.png\" alt=\"Phối cảnh 2 điểm\" />\r\n  </figure>\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/ly-thuyet-phoi-canh/gallery-3-3.png\" alt=\"Phối cảnh 3 điểm\" />\r\n  </figure>\r\n</div>\r\n\r\n<p>Ba loại phối cảnh phổ biến: từ 1 điểm tụ đơn giản đến 3 điểm cho tòa cao ốc. Mỗi loại áp dụng cho tình huống khác nhau.</p>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>02</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Phân loại</p>\r\n    <h2 class=\"div-title\">3 loại phối cảnh</h2>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"pr-table\">\r\n  <div class=\"pr-row\"><span class=\"pr-i\">i.</span><div class=\"pr-n\">Phối cảnh 1 điểm<small>One-point</small></div><div class=\"pr-d\">Người xem nhìn thẳng vào vật. Tất cả đường ngang đi về 1 điểm tụ duy nhất. Dùng cho hành lang, đường phố.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">ii.</span><div class=\"pr-n\">Phối cảnh 2 điểm<small>Two-point</small></div><div class=\"pr-d\">Người xem nhìn xiên, vật có 2 cạnh hướng về 2 điểm tụ trên đường chân trời. Dùng cho nhà, đồ vật nhìn từ góc.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">iii.</span><div class=\"pr-n\">Phối cảnh 3 điểm<small>Three-point</small></div><div class=\"pr-d\">Thêm điểm tụ thứ 3 ở trên hoặc dưới. Dùng để diễn tả độ cao.</div></div>\r\n</div>\r\n\r\n<!-- 🖼️ MOSAIC · Lịch sử Renaissance -->\r\n<div class=\"mosaic\">\r\n  <div class=\"mosaic-big\">\r\n    <img src=\"/img/ly-thuyet-phoi-canh/mosaic-1.png\" alt=\"Brunelleschi 1415\" />\r\n  </div>\r\n  <div class=\"mosaic-small\">\r\n    <img src=\"/img/ly-thuyet-phoi-canh/mosaic-2.png\" alt=\"Notre Dame sketch\" />\r\n  </div>\r\n  <div class=\"mosaic-small\">\r\n    <img src=\"/img/ly-thuyet-phoi-canh/mosaic-3.png\" alt=\"School of Athens\" />\r\n  </div>\r\n</div>\r\n  \r\n</div>\r\n\r\n<p>Trước 1415, tranh phương Tây <strong>không có phối cảnh đúng</strong>. Kiến trúc sư Filippo Brunelleschi đã hệ thống hoá lại phối cảnh — và mọi thứ thay đổi. Leonardo, Raphael, Michelangelo đều xây dựng tranh dựa trên phối cảnh chuẩn.</p>\r\n\r\n<div class=\"pq\">\r\n  <p class=\"pq-text\">Phối cảnh không phải nghệ thuật — nó là <em>hình học ứng dụng</em> vào nghệ thuật.</p>\r\n  <span class=\"pq-cite\">— Filippo Brunelleschi, 1415</span>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>03</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Ứng dụng</p>\r\n    <h2 class=\"div-title\">Khi nào dùng loại nào?</h2>\r\n  </div>\r\n</div>\r\n\r\n<!-- SAI (hiện tại) -->\r\n<div class=\"el-intro\">4 Tình huống phổ biến và loại phối cảnh phù hợp.</div>\r\n\r\n<!-- ĐÚNG -->\r\n<div class=\"el-intro\">\r\n  <div class=\"el-intro-n\">4</div>\r\n  <p class=\"el-intro-t\">Tình huống phổ biến và loại phối cảnh phù hợp.</p>\r\n</div>\r\n\r\n<div class=\"el-list\">\r\n\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">01</span>\r\n      <p class=\"el-name\">Phòng nhìn thẳng <em>Interior</em></p>\r\n      <p class=\"el-desc\">Phối cảnh 1 điểm. Bạn đứng giữa phòng nhìn vào tường đối diện.</p>\r\n    </div>\r\n    <div class=\"el-item-img\">\r\n      <img src=\"/img/ly-thuyet-phoi-canh/el-01.png\" alt=\"Phối cảnh 1 điểm\" loading=\"lazy\" decoding=\"async\" />\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">02</span>\r\n      <p class=\"el-name\">Ngôi nhà ngoài đường <em>Exterior</em></p>\r\n      <p class=\"el-desc\">Phối cảnh 2 điểm. Hai mặt của ngôi nhà đều thấy, mỗi mặt có 1 điểm tụ riêng.</p>\r\n    </div>\r\n    <div class=\"el-item-img\">\r\n      <img src=\"/img/ly-thuyet-phoi-canh/el-02.png\" alt=\"Phối cảnh 2 điểm\" loading=\"lazy\" decoding=\"async\" />\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">03</span>\r\n      <p class=\"el-name\">Tòa cao ốc <em>Skyscraper</em></p>\r\n      <p class=\"el-desc\">Phối cảnh 3 điểm. Nhìn lên — điểm tụ thứ 3 ở trên.</p>\r\n    </div>\r\n    <div class=\"el-item-img\">\r\n      <img src=\"/img/ly-thuyet-phoi-canh/el-03.png\" alt=\"Phối cảnh 3 điểm\" loading=\"lazy\" decoding=\"async\" />\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">04</span>\r\n      <p class=\"el-name\">Tĩnh vật trên bàn <em>Still life</em></p>\r\n      <p class=\"el-desc\">Phối cảnh 2 điểm tinh tế. Các đồ vật nhỏ vẫn tuân theo.</p>\r\n    </div>\r\n    <div class=\"el-item-img\">\r\n      <img src=\"/img/ly-thuyet-phoi-canh/el-04.png\" alt=\"Tĩnh vật\" loading=\"lazy\" decoding=\"async\" />\r\n    </div>\r\n  </div>\r\n\r\n</div>\r\n\r\n<div class=\"tips\">\r\n  <div class=\"tip\"><span class=\"tip-n\">01</span><div class=\"tip-c\"><p class=\"tip-t\">Xác định đường chân trời trước</p><p class=\"tip-d\">Luôn vẽ đường chân trời đầu tiên. Nó là ngang tầm mắt — quyết định mọi điểm tụ.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">02</span><div class=\"tip-c\"><p class=\"tip-t\">Điểm tụ nằm xa</p><p class=\"tip-d\">Trong phối cảnh 2 điểm, đặt 2 điểm tụ xa nhau — thường ngoài giấy — để tránh biến dạng.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">03</span><div class=\"tip-c\"><p class=\"tip-t\">Vẽ lưới sàn</p><p class=\"tip-d\">Lưới sàn đúng phối cảnh là nền tảng. Mọi vật trên sàn sẽ tự đúng nếu lưới đúng.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">04</span><div class=\"tip-c\"><p class=\"tip-t\">Luyện mắt bằng ảnh</p><p class=\"tip-d\">Chụp ảnh đường phố, đồ vật — vẽ đường chân trời và điểm tụ lên ảnh.</p></div></div>\r\n</div>\r\n\r\n<div class=\"dd break-half\">\r\n  <div class=\"dd-col good\">\r\n    <div class=\"dd-head\"><span class=\"dd-badge\">+</span><span class=\"dd-title\">Nên làm</span></div>\r\n    <ul class=\"dd-list\">\r\n      <li>Luôn xác định đường chân trời trước</li>\r\n      <li>Dùng thước vẽ đường thẳng chính xác ban đầu</li>\r\n      <li>Vẽ điểm tụ dù nó nằm ngoài giấy</li>\r\n      <li>Học phối cảnh 1-2 điểm thật kỹ trước 3 điểm</li>\r\n    </ul>\r\n  </div>\r\n  <div class=\"dd-col bad\">\r\n    <div class=\"dd-head\"><span class=\"dd-badge\">−</span><span class=\"dd-title\">Nên tránh</span></div>\r\n    <ul class=\"dd-list\">\r\n      <li>Bỏ qua đường chân trời, vẽ \"cảm giác\"</li>\r\n      <li>Đặt 2 điểm tụ quá gần → biến dạng fish-eye</li>\r\n      <li>Nhảy thẳng vào 3 điểm khi chưa vững 1-2 điểm</li>\r\n      <li>Cho rằng mọi vật đều cùng chung điểm tụ</li>\r\n    </ul>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"key break\">\r\n  <p class=\"key-lbl\">⭐ Điểm mấu chốt</p>\r\n  <p class=\"key-t\">Phối cảnh là <em>luật chơi không đổi</em> của mọi không gian 3D.</p>\r\n  <p class=\"key-d\">Một khi thuần thục, bạn vẽ được bất kỳ cảnh nào — dù có mẫu hay không. Đây là kỹ năng bắt buộc cho kiến trúc, concept art, nội thất và minh hoạ không gian.</p>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>04</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">FAQ</p>\r\n    <h2 class=\"div-title\">Câu hỏi thường gặp</h2>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"faq\">\r\n  <details open>\r\n    <summary>Vẽ nhân vật có cần học phối cảnh không?<span class=\"faq-icon\">−</span></summary>\r\n    <p>Có. Nhân vật luôn đứng trong không gian, và các phần cơ thể đều tuân theo phối cảnh khi nhìn từ góc xiên. Foreshortening là phần khó nhất của vẽ nhân vật.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Phối cảnh 4, 5 điểm có tồn tại không?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Có — phối cảnh ngư nhãn dùng 4-5 điểm để diễn tả góc nhìn cực rộng. Phổ biến hơn ở concept art và manga.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Có app nào hỗ trợ vẽ phối cảnh?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Procreate có Drawing Guide với perspective. Clip Studio Paint có Perspective Ruler mạnh nhất. Concepts app cho iPad cũng có hệ lưới phối cảnh linh hoạt.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Bao lâu để thành thục phối cảnh?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Hiểu lý thuyết: vài buổi. Vẽ phối cảnh 1-2 điểm thành thạo: 2-3 tháng. Vẽ 3 điểm và foreshortening tự nhiên: 1-2 năm luyện tập đều đặn.</p>\r\n  </details>\r\n</div>\r\n";

